import { Grid } from "@mui/material";
import { Typography } from "@mui/material";
import { Chip, Avatar } from "@mui/material";
import React from "react";
import SensorReadings from "../SensorReadings/SensorReadings"
const BasicInfo = () => {
  // const theme = createTheme({
  //   typography: {
  //     fontFamily: ["Inter"],
  //   },
  // });
  return (
    <>
      <Grid container>
        <Grid item md={6} xs={12} sx={{ p: { md: 7, xs: 3 } }}>
          <Typography variant="h4" fontWeight={700} sx={{textAlign : {xs : "center", md:"left"}}} gutterBottom>
            End-to-End content needs for you. 
          </Typography>
          <Typography variant="subtitle1" sx={{textAlign : {xs : "center", md:"left"}}}>
          Colourisko offers a one-stop shop for content-related services.
Leverage the network of our writers to get the best content fast. Unlimited revisions, quality content, multiple checks and fast deliveries!

          </Typography>
        </Grid>
        <Grid
          item
          md={6}
          xs={12}
          sx={{
            display: "flex",
            justifyContent: { md: "end", xs: "center" },
            alignItems: "center",
          }}
        >
          <form onSubmit={handleSubmit}>
      <input
        aria-label="Your first name"
        name="fields[first_name]"
        placeholder="Your first name"
        type="text"
        onChange={handleNameChange}
        value={name}
      />
      <input
        aria-label="Your email address"
        name="email_address"
        placeholder="Your email address"
        required
        type="email"
        onChange={handleEmailChange}
        value={email}
      />
      <button>SUBSCRIBE</button>
    </form>
        </Grid>
      </Grid>
      <SensorReadings/>
    </>
  );
};

export default BasicInfo;
